import React from 'react';
import { Outlet, Link, useLocation, useNavigate } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';

const navItems = [
  { to: '/admin',            icon: '📊', label: 'Dashboard' },
  { to: '/admin/users',      icon: '👥', label: 'Users' },
  { to: '/admin/products',   icon: '📦', label: 'Products' },
  { to: '/admin/orders',     icon: '🛒', label: 'Orders' },
  { to: '/admin/categories', icon: '🗂', label: 'Categories' },
  { to: '/admin/coupons',    icon: '🎟', label: 'Coupons' },
  { to: '/admin/shops',      icon: '🏪', label: 'Shops' },
  { to: '/admin/warehouses', icon: '🏬', label: 'Warehouses' },
  { to: '/admin/inventory',  icon: '📈', label: 'Inventory' },
  { to: '/admin/logistics',  icon: '🚚', label: 'Logistics' },
  { to: '/admin/staff',      icon: '🧑‍💼', label: 'Staff' },
  { to: '/admin/expenses',   icon: '🧾', label: 'Expenses' },
  { to: '/admin/finance',    icon: '💳', label: 'Finance' },
];

export default function AdminLayout() {
  const { user, logout } = useAuth();
  const location = useLocation();
  const navigate = useNavigate();

  const handleLogout = async () => { await logout(); navigate('/login'); };

  return (
    <div style={{ display: 'flex', minHeight: '100vh', background: 'var(--gray-50)' }}>
      {/* Sidebar */}
      <aside style={{ width: 240, background: 'var(--green-900)', color: 'white', display: 'flex', flexDirection: 'column', position: 'sticky', top: 0, height: '100vh' }}>
        <div style={{ padding: '1.5rem 1.25rem', borderBottom: '1px solid rgba(255,255,255,0.1)' }}>
          <div style={{ fontFamily: 'Syne, sans-serif', fontSize: '1.2rem', fontWeight: 800 }}>🌾 AgroMart</div>
          <div style={{ fontSize: '0.75rem', color: 'rgba(255,255,255,0.5)', marginTop: '0.25rem' }}>Admin Panel</div>
        </div>
        <nav style={{ flex: 1, padding: '1rem 0.75rem' }}>
          {navItems.map(item => {
            const isActive = location.pathname === item.to;
            return (
              <Link key={item.to} to={item.to} style={{ display: 'flex', alignItems: 'center', gap: '0.75rem', padding: '0.65rem 0.85rem', borderRadius: '10px', marginBottom: '0.25rem', color: isActive ? 'white' : 'rgba(255,255,255,0.65)', background: isActive ? 'rgba(255,255,255,0.15)' : 'none', fontWeight: isActive ? 600 : 400, fontSize: '0.875rem', transition: 'all 0.2s', textDecoration: 'none' }}>
                <span>{item.icon}</span>{item.label}
              </Link>
            );
          })}
        </nav>
        <div style={{ padding: '1rem', borderTop: '1px solid rgba(255,255,255,0.1)' }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem', marginBottom: '0.75rem' }}>
            <img src={user?.avatar} alt={user?.name} style={{ width: 36, height: 36, borderRadius: '50%' }} />
            <div style={{ overflow: 'hidden' }}>
              <div style={{ fontSize: '0.8rem', fontWeight: 600, color: 'white', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{user?.name}</div>
              <div style={{ fontSize: '0.7rem', color: 'rgba(255,255,255,0.5)' }}>Administrator</div>
            </div>
          </div>
          <button onClick={handleLogout} style={{ width: '100%', padding: '0.5rem', background: 'rgba(255,255,255,0.1)', color: 'rgba(255,255,255,0.8)', border: 'none', borderRadius: 8, fontSize: '0.8rem', cursor: 'pointer' }}>🚪 Logout</button>
        </div>
      </aside>

      {/* Main content */}
      <main style={{ flex: 1, padding: '2rem', overflowY: 'auto' }}>
        <Outlet />
      </main>
    </div>
  );
}
